Object.assign(window.I18N.en,{turntableTitle:"8-View Continuity Check",turntableText:"Compare eight angles to keep the same character recognisable in every scene.",dragHint:"↔ Drag or use the arrows",ratioShowcaseTitle:"One campaign, every retail format",ratioShowcaseText:"Choose the output ratio before generating so the composition has the correct space for product, copy and CTA.",ratioUseSquare:"Social post",ratioUsePortrait:"Feed portrait",ratioUseVertical:"Reels / Stories",ratioUseWide:"Website / video",ratioUsePrint:"Leaflet / catalogue","Negative Prompt & Guardrails":"Negative Prompt & Guardrails","Custom Negative Prompt":"Custom Negative Prompt","Choose guardrails…":"Choose guardrails…","choose multiple":"choose multiple",promptLabEyebrow:"Visual Prompt Lab",promptLabTitle:"See what a good prompt changes",promptLabIntro:"A vague prompt leaves the model to guess. A production prompt fixes the product, character, composition, ratio and guardrails before generation.",badPromptLabel:"Weak prompt",badPromptTitle:"Too much is left to chance",badPromptExample:"“Make a nice picture of a person holding our product in a shop.”",badPromptPoint1:"No product shape, material or label rules",badPromptPoint2:"No character or hand guidance",badPromptPoint3:"No ratio, composition or negative prompt",goodPromptLabel:"Production prompt",goodPromptTitle:"Every important decision is controlled",goodPromptExample:"“Create a 4:3 retail hero. Keep the white cylindrical pump bottle, teal label block and pump direction identical. Show a professional presenter with natural hands. Use clean navy-and-cream retail lighting. No cropped product, altered label, extra fingers, fake logo or unreadable text.”",goodPromptPoint1:"Exact product continuity and character direction",goodPromptPoint2:"Clear output ratio, composition and lighting",goodPromptPoint3:"Negative prompts prevent common errors",storyToScreenTitle:"From plan to screen",storyToScreenIntro:"Each setting answers a different production question. Scroll through the sequence before building your own prompt.",learnProductFrame:"What must stay accurate?",learnCharacterFrame:"Who must stay recognisable?",learnStoryboardFrame:"What happens in each scene?",learnVideoFrame:"How should it move and finish?",learnRatioTitle:"The ratio changes the composition",learnRatioIntro:"Choose the destination first so important product and copy areas are not cropped later."});
Object.assign(window.I18N["zh-Hant"],{turntableTitle:"八視角連貫性檢查",turntableText:"比較八個角度，確保同一角色在每個場景都保持可辨識。",dragHint:"↔ 拖動或使用箭嘴",ratioShowcaseTitle:"一個活動，配合所有零售格式",ratioShowcaseText:"生成前先選擇輸出比例，讓產品、文案及行動呼籲保留正確空間。",ratioUseSquare:"社交帖文",ratioUsePortrait:"直向動態帖文",ratioUseVertical:"短片／限時動態",ratioUseWide:"網站／影片",ratioUsePrint:"單張／目錄","Negative Prompt & Guardrails":"負面提示詞及防錯規則","Custom Negative Prompt":"自訂負面提示詞","Choose guardrails…":"選擇防錯規則…","choose multiple":"可選多項",promptLabEyebrow:"視覺提示詞實驗室",promptLabTitle:"看看好提示詞帶來甚麼改變",promptLabIntro:"模糊提示詞會讓模型自行猜測；製作級提示詞會在生成前鎖定產品、角色、構圖、比例及防錯規則。",badPromptLabel:"薄弱提示詞",badPromptTitle:"太多重要決定交由模型猜測",badPromptExample:"「製作一張人物在店內手持我們產品的漂亮圖片。」",badPromptPoint1:"沒有產品形狀、物料或標籤規則",badPromptPoint2:"沒有角色或手部指示",badPromptPoint3:"沒有比例、構圖或負面提示詞",goodPromptLabel:"製作級提示詞",goodPromptTitle:"每個重要決定都有清楚控制",goodPromptExample:"「製作 4:3 零售主視覺。保持白色圓柱泵瓶、藍綠色標籤區及泵頭方向完全一致。展示專業主持人及自然手部。使用乾淨海軍藍與米白色零售燈光。不要裁切產品、改變標籤、額外手指、虛構標誌或不可讀文字。」",goodPromptPoint1:"準確產品連貫性及角色方向",goodPromptPoint2:"清楚輸出比例、構圖及燈光",goodPromptPoint3:"負面提示詞可防止常見錯誤",storyToScreenTitle:"從計劃到畫面",storyToScreenIntro:"每項設定回答不同的製作問題。建立提示詞前，先了解完整次序。",learnProductFrame:"甚麼必須保持準確？",learnCharacterFrame:"誰必須保持可辨識？",learnStoryboardFrame:"每個場景發生甚麼？",learnVideoFrame:"畫面如何移動及完成？",learnRatioTitle:"比例會改變構圖",learnRatioIntro:"先選擇輸出平台，避免重要產品及文案位置其後被裁走。"});
Object.assign(window.I18N["zh-Hans"],{turntableTitle:"八视角连贯性检查",turntableText:"比较八个角度，确保同一角色在每个场景都保持可识别。",dragHint:"↔ 拖动或使用箭头",ratioShowcaseTitle:"一个活动，适配所有零售格式",ratioShowcaseText:"生成前先选择输出比例，让产品、文案及行动号召保留正确空间。",ratioUseSquare:"社交帖子",ratioUsePortrait:"竖版动态帖子",ratioUseVertical:"短视频／限时动态",ratioUseWide:"网站／视频",ratioUsePrint:"宣传单／目录","Negative Prompt & Guardrails":"负面提示词及防错规则","Custom Negative Prompt":"自定义负面提示词","Choose guardrails…":"选择防错规则…","choose multiple":"可选多项",promptLabEyebrow:"视觉提示词实验室",promptLabTitle:"看看好提示词带来什么改变",promptLabIntro:"模糊提示词会让模型自行猜测；制作级提示词会在生成前锁定产品、角色、构图、比例及防错规则。",badPromptLabel:"薄弱提示词",badPromptTitle:"太多重要决定交由模型猜测",badPromptExample:"“制作一张人物在店内手持我们产品的漂亮图片。”",badPromptPoint1:"没有产品形状、材料或标签规则",badPromptPoint2:"没有角色或手部指示",badPromptPoint3:"没有比例、构图或负面提示词",goodPromptLabel:"制作级提示词",goodPromptTitle:"每个重要决定都有清楚控制",goodPromptExample:"“制作 4:3 零售主视觉。保持白色圆柱泵瓶、蓝绿色标签区及泵头方向完全一致。展示专业主持人及自然手部。使用干净海军蓝与米白色零售灯光。不要裁切产品、改变标签、额外手指、虚构标志或不可读文字。”",goodPromptPoint1:"准确产品连贯性及角色方向",goodPromptPoint2:"清楚输出比例、构图及灯光",goodPromptPoint3:"负面提示词可防止常见错误",storyToScreenTitle:"从计划到画面",storyToScreenIntro:"每项设置回答不同的制作问题。建立提示词前，先了解完整顺序。",learnProductFrame:"什么必须保持准确？",learnCharacterFrame:"谁必须保持可识别？",learnStoryboardFrame:"每个场景发生什么？",learnVideoFrame:"画面如何移动及完成？",learnRatioTitle:"比例会改变构图",learnRatioIntro:"先选择输出平台，避免重要产品及文案位置之后被裁掉。"});
Object.assign(window.I18N.ja,{turntableTitle:"8方向の一貫性チェック",turntableText:"8つの角度を比較し、全シーンで同じ人物だと認識できる状態を保ちます。",dragHint:"↔ ドラッグまたは矢印を使用",ratioShowcaseTitle:"1つのキャンペーンを全小売形式へ",ratioShowcaseText:"生成前に出力比率を選び、製品・コピー・CTAの正しいスペースを確保します。",ratioUseSquare:"SNS投稿",ratioUsePortrait:"フィード縦型",ratioUseVertical:"リール／ストーリーズ",ratioUseWide:"ウェブ／動画",ratioUsePrint:"リーフレット／カタログ","Negative Prompt & Guardrails":"ネガティブプロンプトと防止ルール","Custom Negative Prompt":"カスタムネガティブプロンプト","Choose guardrails…":"防止ルールを選択…","choose multiple":"複数選択可",promptLabEyebrow:"ビジュアル・プロンプトラボ",promptLabTitle:"良いプロンプトが変えるもの",promptLabIntro:"曖昧なプロンプトはモデルに推測させます。制作プロンプトは生成前に製品、人物、構図、比率、防止ルールを固定します。",badPromptLabel:"弱いプロンプト",badPromptTitle:"重要な判断を偶然に任せている",badPromptExample:"「店で人物が製品を持つ、きれいな画像を作って。」",badPromptPoint1:"製品形状・素材・ラベルのルールがない",badPromptPoint2:"人物や手の指示がない",badPromptPoint3:"比率・構図・ネガティブ指示がない",goodPromptLabel:"制作プロンプト",goodPromptTitle:"重要な判断をすべて管理",goodPromptExample:"「4:3の小売ヒーロー画像。白い円筒ポンプボトル、青緑のラベル領域、ポンプ方向を同一に保つ。自然な手のプロのプレゼンター。ネイビーとクリームの清潔な小売照明。製品切れ、ラベル変更、余分な指、偽ロゴ、読めない文字は禁止。」",goodPromptPoint1:"正確な製品連続性と人物指示",goodPromptPoint2:"明確な出力比率・構図・照明",goodPromptPoint3:"ネガティブ指示で一般的な失敗を防止",storyToScreenTitle:"計画から画面へ",storyToScreenIntro:"各設定は異なる制作上の問いに答えます。プロンプト作成前に順序を確認しましょう。",learnProductFrame:"何を正確に保つ？",learnCharacterFrame:"誰を同一人物として保つ？",learnStoryboardFrame:"各シーンで何が起きる？",learnVideoFrame:"どう動き、どう終える？",learnRatioTitle:"比率で構図が変わる",learnRatioIntro:"重要な製品やコピー領域が後で切れないよう、最初に掲載先を選びます。"});
Object.assign(window.I18N.ko,{turntableTitle:"8방향 일관성 확인",turntableText:"8개 각도를 비교해 모든 장면에서 같은 캐릭터로 인식되도록 유지하세요.",dragHint:"↔ 드래그하거나 화살표 사용",ratioShowcaseTitle:"하나의 캠페인, 모든 리테일 형식",ratioShowcaseText:"생성 전에 출력 비율을 선택해 제품, 카피, CTA를 위한 올바른 공간을 확보하세요.",ratioUseSquare:"소셜 게시물",ratioUsePortrait:"피드 세로형",ratioUseVertical:"릴스／스토리",ratioUseWide:"웹사이트／영상",ratioUsePrint:"리플릿／카탈로그","Negative Prompt & Guardrails":"네거티브 프롬프트 및 방지 규칙","Custom Negative Prompt":"사용자 네거티브 프롬프트","Choose guardrails…":"방지 규칙 선택…","choose multiple":"복수 선택",promptLabEyebrow:"비주얼 프롬프트 랩",promptLabTitle:"좋은 프롬프트가 만드는 차이",promptLabIntro:"모호한 프롬프트는 모델이 추측하게 합니다. 제작용 프롬프트는 생성 전에 제품, 캐릭터, 구도, 비율과 방지 규칙을 고정합니다.",badPromptLabel:"약한 프롬프트",badPromptTitle:"너무 많은 결정을 우연에 맡깁니다",badPromptExample:"“매장에서 사람이 우리 제품을 들고 있는 멋진 사진을 만들어 줘.”",badPromptPoint1:"제품 형태, 소재, 라벨 규칙 없음",badPromptPoint2:"캐릭터나 손 지시 없음",badPromptPoint3:"비율, 구도, 네거티브 프롬프트 없음",goodPromptLabel:"제작용 프롬프트",goodPromptTitle:"모든 중요한 결정을 제어합니다",goodPromptExample:"“4:3 리테일 히어로 이미지를 만드세요. 흰색 원통형 펌프 병, 청록 라벨 블록, 펌프 방향을 동일하게 유지하세요. 자연스러운 손의 전문 진행자를 보여 주세요. 깔끔한 네이비와 크림 리테일 조명을 사용하세요. 제품 잘림, 라벨 변경, 추가 손가락, 가짜 로고, 읽을 수 없는 글자는 금지합니다.”",goodPromptPoint1:"정확한 제품 연속성과 캐릭터 지시",goodPromptPoint2:"명확한 출력 비율, 구도와 조명",goodPromptPoint3:"네거티브 프롬프트로 흔한 오류 방지",storyToScreenTitle:"계획에서 화면까지",storyToScreenIntro:"각 설정은 서로 다른 제작 질문에 답합니다. 프롬프트를 만들기 전에 순서를 확인하세요.",learnProductFrame:"무엇을 정확하게 유지해야 하나요?",learnCharacterFrame:"누가 계속 동일해야 하나요?",learnStoryboardFrame:"각 장면에서 무엇이 일어나나요?",learnVideoFrame:"어떻게 움직이고 끝내나요?",learnRatioTitle:"비율이 구도를 바꿉니다",learnRatioIntro:"중요한 제품과 카피 영역이 잘리지 않도록 먼저 게시 위치를 선택하세요."});

const negativeChoiceTranslations={"Face or identity drift":["臉部或身份漂移","脸部或身份漂移","顔・人物の変化","얼굴 또는 정체성 변화"],"Age or body shape changes":["年齡或身形改變","年龄或身形改变","年齢・体型の変化","나이 또는 체형 변화"],"Hair or clothing changes":["髮型或服裝改變","发型或服装改变","髪型・服装の変化","헤어 또는 의상 변화"],"Distorted hands or extra fingers":["手部變形或額外手指","手部变形或额外手指","手の歪み・余分な指","왜곡된 손 또는 추가 손가락"],"Unnatural anatomy or pose":["不自然人體或姿勢","不自然人体或姿势","不自然な人体・ポーズ","부자연스러운 신체 또는 포즈"],"Plastic skin or over-retouching":["塑膠皮膚或過度修圖","塑料皮肤或过度修图","プラスチック肌・過剰修整","플라스틱 피부 또는 과도한 보정"],"Changed product shape or scale":["產品形狀或比例改變","产品形状或比例改变","製品形状・縮尺の変化","제품 형태 또는 비율 변경"],"Altered label, logo or colors":["標籤、標誌或顏色改變","标签、标志或颜色改变","ラベル・ロゴ・色の変更","라벨, 로고 또는 색상 변경"],"Wrong material or surface finish":["錯誤物料或表面處理","错误材料或表面处理","誤った素材・表面仕上げ","잘못된 소재 또는 표면 마감"],"Invented features or certifications":["虛構功能或認證","虚构功能或认证","架空の機能・認証","조작된 기능 또는 인증"],"Unsupported claims or prices":["未經支持的聲稱或價格","未经支持的声称或价格","未確認の主張・価格","근거 없는 주장 또는 가격"],"Cropped product or hidden label":["產品被裁切或標籤被遮擋","产品被裁切或标签被遮挡","製品切れ・ラベル隠れ","잘린 제품 또는 가려진 라벨"],"Missing or reordered scenes":["場景缺失或次序改變","场景缺失或顺序改变","シーン欠落・順序変更","장면 누락 또는 순서 변경"],"Character continuity break":["角色連貫性中斷","角色连贯性中断","人物の連続性崩れ","캐릭터 연속성 단절"],"Product continuity break":["產品連貫性中斷","产品连贯性中断","製品の連続性崩れ","제품 연속성 단절"],"Unclear action or focal point":["動作或焦點不清","动作或焦点不清","動作・焦点が不明確","불분명한 동작 또는 초점"],"Missing voiceover or on-screen text":["遺漏旁白或畫面文字","遗漏旁白或画面文字","ナレーション・画面文字の欠落","내레이션 또는 화면 텍스트 누락"],"Unsupported product claim":["未經支持的產品聲稱","未经支持的产品声称","未確認の製品主張","근거 없는 제품 주장"],"Flicker, morphing or jitter":["閃爍、變形或抖動","闪烁、变形或抖动","ちらつき・変形・揺れ","깜박임, 변형 또는 흔들림"],"Face, clothing or identity drift":["臉部、服裝或身份漂移","脸部、服装或身份漂移","顔・服装・人物の変化","얼굴, 의상 또는 정체성 변화"],"Warped hands or anatomy":["手部或人體扭曲","手部或人体扭曲","手・人体の歪み","왜곡된 손 또는 신체"],"Changed packaging or unreadable label":["包裝改變或標籤不可讀","包装改变或标签不可读","包装変更・読めないラベル","포장 변경 또는 읽을 수 없는 라벨"],"Sudden camera shake or jump cuts":["突然鏡頭震動或跳剪","突然镜头抖动或跳剪","急な手ぶれ・ジャンプカット","갑작스러운 카메라 흔들림 또는 점프 컷"],"Unreadable generated text or lip-sync errors":["不可讀生成文字或對嘴錯誤","不可读生成文字或对口型错误","読めない生成文字・口同期ずれ","읽을 수 없는 생성 텍스트 또는 립싱크 오류"]};
Object.entries(negativeChoiceTranslations).forEach(([english,values])=>values.forEach((value,index)=>window.I18N[["zh-Hant","zh-Hans","ja","ko"][index]][english]=value));

const builderTextTranslations={
"Define who appears, how they look and how they behave.":["定義出現的人物、外觀及行為。","定义出现的人物、外观及行为。","登場人物の外見と行動を定義します。","등장인물의 외형과 행동을 정의합니다."],
"Create a consistent, realistic character concept for a marketing visual.":["為推廣視覺建立一致而寫實的角色概念。","为营销视觉建立一致而写实的角色概念。","マーケティング画像向けに一貫した写実的な人物を作成します。","마케팅 비주얼을 위한 일관되고 사실적인 캐릭터를 만드세요."],
"Keep anatomy, hands, facial features, clothing and character continuity realistic and consistent.":["保持人體、手部、五官、服裝及角色連貫性寫實一致。","保持人体、手部、五官、服装及角色连贯性写实一致。","人体、手、顔、服装、人物の連続性を写実的かつ一貫させます。","신체, 손, 얼굴, 의상과 캐릭터 연속성을 사실적이고 일관되게 유지하세요."],
"Define the product itself—its features, shape, materials, packaging and exact appearance. Character information belongs in Character Setting.":["只定義產品本身——功能、形狀、物料、包裝及準確外觀。角色資料應放在角色設定。","只定义产品本身——功能、形状、材料、包装及准确外观。角色信息应放在角色设置。","製品の特徴、形状、素材、包装、正確な外観を定義します。人物情報はキャラクター設定に入力します。","제품의 특징, 형태, 소재, 포장과 정확한 외관을 정의합니다. 인물 정보는 캐릭터 설정에 입력하세요."],
"Create an accurate product specification and campaign-ready product visual using the supplied reference as the source of truth.":["以提供的參考圖為準，建立準確產品規格及可用於活動的產品視覺。","以提供的参考图为准，建立准确产品规格及可用于活动的产品视觉。","提供された参考画像を基準に、正確な製品仕様とキャンペーン用画像を作成します。","제공된 참고 이미지를 기준으로 정확한 제품 사양과 캠페인용 비주얼을 만드세요."],
"Show the product only unless another linked builder explicitly adds a character. Preserve exact shape, scale, materials, surface finish, packaging artwork, label placement, closure and colours. Never invent features, certifications, logos, prices, claims or product text.":["除非連結的其他設定明確加入角色，否則只顯示產品。準確保留形狀、比例、物料、表面、包裝設計、標籤位置、封口及顏色。不可虛構功能、認證、標誌、價格、聲稱或產品文字。","除非链接的其他设置明确加入角色，否则只显示产品。准确保留形状、比例、材料、表面、包装设计、标签位置、封口及颜色。不可虚构功能、认证、标志、价格、声明或产品文字。","連携設定で人物を明示しない限り製品のみを表示します。形状、比率、素材、表面、包装、ラベル位置、開閉部、色を正確に保ち、機能、認証、ロゴ、価格、主張、製品文字を創作しません。","연결된 설정에서 인물을 명시하지 않는 한 제품만 표시하세요. 형태, 비율, 소재, 표면, 포장, 라벨 위치, 마개와 색상을 정확히 유지하고 기능, 인증, 로고, 가격, 주장이나 제품 문구를 만들지 마세요."],
"Link saved Character and Product Settings, then describe every scene with timing, shot size, action and voiceover.":["連結已儲存的角色及產品設定，再逐場景說明時間、景別、動作及旁白。","链接已保存的角色及产品设置，再逐场景说明时间、景别、动作及旁白。","保存済みの人物・製品設定を連携し、各シーンの時間、ショット、動作、ナレーションを記述します。","저장된 캐릭터와 제품 설정을 연결한 뒤 각 장면의 시간, 샷 크기, 동작과 내레이션을 설명하세요."],
"Create a production-ready, scene-by-scene storyboard using the linked Character and Product Settings as continuity references.":["以連結的角色及產品設定作為連貫參考，建立可直接製作的逐場景分鏡。","以链接的角色及产品设置作为连贯参考，建立可直接制作的逐场景分镜。","連携した人物・製品設定を連続性基準として、制作可能なシーン別絵コンテを作成します。","연결된 캐릭터와 제품 설정을 연속성 기준으로 사용해 제작 가능한 장면별 스토리보드를 만드세요."],
"For every scene, state the timing, shot size, scene description, subject action, product placement, camera direction, transition and exact voiceover. Maintain the linked character identity and linked product shape, materials, label and colours throughout.":["每個場景列明時間、景別、畫面描述、主體動作、產品位置、鏡頭方向、轉場及準確旁白。全程保持連結角色身份，以及產品形狀、物料、標籤及顏色。","每个场景列明时间、景别、画面描述、主体动作、产品位置、镜头方向、转场及准确旁白。全程保持链接角色身份，以及产品形状、材料、标签及颜色。","各シーンで時間、ショット、説明、動作、製品位置、カメラ、転換、正確な台詞を示し、人物と製品形状・素材・ラベル・色を維持します。","각 장면에 시간, 샷 크기, 설명, 동작, 제품 위치, 카메라 방향, 전환과 정확한 대사를 명시하고 캐릭터 및 제품 형태, 소재, 라벨과 색상을 유지하세요."],
"Core Story / Campaign Message":["核心故事／活動訊息","核心故事／活动信息","中心ストーリー／キャンペーンメッセージ","핵심 이야기／캠페인 메시지"],"Primary Scene Action":["主要場景動作","主要场景动作","主なシーン動作","주요 장면 동작"],"Story Beats / Continuity Rules":["情節重點／連貫規則","情节重点／连贯规则","展開／連続性ルール","이야기 전개／연속성 규칙"],
"Link the Character, Product and Storyboard Settings to generate one complete, production-ready video prompt.":["連結角色、產品及分鏡設定，生成一個完整且可直接製作的影片提示詞。","链接角色、产品及分镜设置，生成一个完整且可直接制作的视频提示词。","人物・製品・絵コンテ設定を連携し、制作可能な完全動画プロンプトを生成します。","캐릭터, 제품과 스토리보드 설정을 연결해 완전한 제작용 영상 프롬프트를 생성하세요."],
"Create a complete AI video-generation prompt using the linked Character, Product and Storyboard Settings below as the source of truth.":["以下方連結的角色、產品及分鏡設定為準，建立完整 AI 影片生成提示詞。","以下方链接的角色、产品及分镜设置为准，建立完整 AI 视频生成提示词。","以下の連携済み人物・製品・絵コンテ設定を基準に、完全なAI動画生成プロンプトを作成します。","아래의 연결된 캐릭터, 제품과 스토리보드 설정을 기준으로 완전한 AI 영상 생성 프롬프트를 만드세요."],
"Follow the linked storyboard scene by scene. Maintain the linked character identity and product specification in every frame. Use believable motion and stable focus. Avoid flicker, morphing, jitter, warped anatomy or packaging, unreadable generated text and unsupported claims.":["逐場景跟隨連結分鏡，在每格保持角色身份及產品規格。使用可信動作及穩定對焦，避免閃爍、變形、抖動、人體或包裝扭曲、不可讀文字及未經支持聲稱。","逐场景跟随链接分镜，在每帧保持角色身份及产品规格。使用可信动作及稳定对焦，避免闪烁、变形、抖动、人体或包装扭曲、不可读文字及未经支持的声明。","連携絵コンテに沿い、全フレームで人物と製品仕様を維持します。自然な動きと安定した焦点を使い、ちらつき、変形、揺れ、人体・包装の歪み、読めない文字、未確認の主張を避けます。","연결된 스토리보드를 장면별로 따르고 모든 프레임에서 캐릭터와 제품 사양을 유지하세요. 자연스러운 움직임과 안정된 초점을 사용하고 깜박임, 변형, 흔들림, 신체나 포장 왜곡, 읽을 수 없는 텍스트와 근거 없는 주장을 피하세요."],
"Video Treatment":["影片表現方式","视频表现方式","動画表現","영상 표현"]};
