Object.assign(window.I18N.en,{heroRetailTitle:"Build consistent AI videos from product to final scene.",heroRetailText:"Create Product, Character and Storyboard Sheets, then combine them into a production-ready prompt for your chosen AI video tool.",ratioUseBanner:"EDM / banner",toolStudioEyebrow:"AI Video Tool Guide",toolStudioTitle:"Choose the tool after you define the production",toolStudioIntro:"Different tools are better at different jobs. Start with your product, character and storyboard requirements, then choose the model that fits.",reviewedDate:"Information reviewed July 2026. Features and access can change.",seedanceDesc:"Multi-shot audio-video generation with text, image, audio and video references.",klingDesc:"Storyboard-led creation with identity, visual and voice control for longer sequences.",veoDesc:"Cinematic generation with creative camera controls, longer videos and native audio.",runwayDesc:"An integrated workflow for generation, iteration, editing and production effects.",fireflyDesc:"Commercially focused generation with camera controls and Creative Cloud integration.",lumaDesc:"Fast native-1080p generation and Modify Video for controlled visual transformations.",tagMultishot:"Multi-shot",tagAudio:"Native audio",tagReferences:"Multimodal references",tagStoryboard:"Storyboard",tagIdentity:"Identity control",tagCinematic:"Cinematic",tagCamera:"Camera control",tagEditing:"Editing",tagConsistency:"Consistency",tagWorkflow:"Creative workflow",tagBrand:"Brand workflow",tagAdobe:"Adobe integration",tagModify:"Modify Video",tagFast:"Fast iteration",officialSite:"Official site ↗",quizEyebrow:"Tool Matcher",quizTitle:"What does your video need most?",quizIntro:"Answer three questions to receive two starting-point suggestions. Always verify current access and usage rights on the official site.",quizPriority:"Main priority",quizAudio:"Dialogue or generated audio",quizMultishot:"Multi-scene storytelling",quizBrand:"Brand and commercial workflow",quizEditing:"Editing an existing video",quizCinematic:"Cinematic visual quality",quizInput:"Main input",quizText:"Text prompt",quizImage:"Product or character images",quizVideo:"Existing video",quizMulti:"Text, image, audio and video references",quizGoal:"Output goal",quizSocial:"Short social video",quizStory:"Multi-scene campaign",quizProduct:"Product demonstration",quizTransform:"Transform existing footage",quizButton:"Match tools",quizResultLabel:"Suggested starting points",quizDefaultResult:"Both support production workflows where multiple scenes, identity and audio direction matter.",matchAudio:"Use Seedance when multi-shot audio-video references matter; use Veo when cinematic control and native audio are the priority.",matchMultishot:"Both are strong starting points for multi-scene structure, identity continuity and audio direction.",matchBrand:"Firefly is useful for commercially focused Adobe workflows; Runway adds broader generation and editing tools.",matchEditing:"Runway supports an integrated editing workflow, while Luma is strong for Modify Video and visual transformation.",matchCinematic:"Veo focuses on cinematic generation and native audio; Runway adds iteration, consistency and editing.",homeCompareTitle:"The prompt changes the result",homeCompareIntro:"Compare a vague request with a production prompt that fixes continuity, composition and guardrails.",seeFullLesson:"See the full lesson →",continuityDemoEyebrow:"Continuity Check",continuityDemoTitle:"Keep the same world in every scene",continuityDemoText:"Use product and character reference sheets to lock the details that must not change.",continuityPoint1:"Product shape, label, material and color",continuityPoint2:"Character face, age, hair and clothing",continuityPoint3:"Scene order, timing and voiceover",negativeDemoEyebrow:"Negative Prompt",negativeDemoTitle:"Tell the model what must not happen",negativeDemoText:"The new multi-select guardrails automatically add common quality and continuity restrictions to your prompt.",negativePoint1:"No distorted hands, flicker or identity drift",negativePoint2:"No changed packaging or invented claims",negativePoint3:"No cropped product or unreadable generated text"});

